            <div>
               <h1 className="text-xl font-black tracking-tighter leading-none">GEOLOG<span className="text-blue-400">PRO</span></h1>
               <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">System dokumentacji geotechnicznej</p>
            </div>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={handlePrint} 
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 px-6 py-2.5 rounded-full text-sm font-black transition-all shadow-lg active:scale-95"
          >
            <Printer size={18} /> GENERUJ PDF / DRUKUJ
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex flex-1 overflow-hidden">

        {/* Sidebar - ukryty w druku */}
        <div className="w-1/3 min-w-[420px] bg-white border-r border-slate-200 flex flex-col z-10 print:hidden shadow-xl">
           <div className="flex p-2 gap-2 bg-slate-50 border-b">
              <button 
                onClick={() => setActiveTab('header')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-xs font-black transition-all ${activeTab === 'header' ? 'bg-white text-blue-600 shadow-sm border border-slate-200' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <Settings size={16} /> METADANE
              </button>
              <button 
                onClick={() => setActiveTab('layers')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-xs font-black transition-all ${activeTab === 'layers' ? 'bg-white text-blue-600 shadow-sm border border-slate-200' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <LayersIcon size={16} /> WARSTWY
              </button>
           </div>

           <div className="flex-1 overflow-y-auto p-4 bg-slate-50/50">
              {activeTab === 'header' ? (
                <div className="animate-in fade-in slide-in-from-left-4 duration-300">
                  <HeaderForm data={data.header} onChange={handleHeaderChange} />
                </div>
              ) : (
                <div className="h-full animate-in fade-in slide-in-from-left-4 duration-300">
                  <LayerForm layers={data.layers} onUpdate={handleLayersUpdate} />
                </div>
              )}
           </div>
        </div>

        {/* Dynamic Preview Area */}
        <div className="flex-1 bg-slate-200/50 p-10 overflow-auto flex justify-center items-start print:p-0 print:m-0 print:bg-white print:block print:overflow-visible">
           {/* Kontener podglądu, który traci transformacje i skalowanie podczas druku */}
           <div className="scale-90 lg:scale-100 origin-top shadow-2xl transition-transform duration-500 print:scale-100 print:transform-none print:shadow-none print:m-0 print:p-0 print-no-transform">
              <ReportPreview data={data} />
           </div>
        </div>

      </div>
    </div>
  );
};

export default App;
